INSERT INTO app_settings(id, settings) VALUES (1, '{"vat_rate":0.22,"k1":0.65,"payroll_tax_rate":0.3,"npd_factor":0.94,"driver_avg_speed_kmh":75.0,"diesel_l_per_100km":15.0,"office_cities":["Казань","Москва"],"office_rates":{"Казань":{"driver_km_rate":15.0,"demo_work_rate":1350.0,"cryoblaster_rate":4000.0,"gazelle_rate":18000.0,"sale_st":0.565,"latitude":55.796127,"longitude":49.106414},"Москва":{"driver_km_rate":20.0,"demo_work_rate":1350.0,"cryoblaster_rate":6000.0,"gazelle_rate":22000.0,"sale_st":0.465,"latitude":55.7987966,"longitude":37.965255}},"font_family":"Arial","ui":{"action_list_width_pct":31,"font_base_px":13,"font_title_px":18,"card_padding_px":10,"field_gap_px":8,"table_row_height_px":30,"criteria_name_width_pct":20,"criteria_levels_width_pct":60,"criteria_comment_width_pct":20,"geo_api_key":""},"criteria":[{"block":"P","code":"P1","title":"Покупающий центр подтвержден","desc":"оценивает, кто со стороны клиента реально участвует в демонстрации и согласовании. Максимальный балл ставится только если есть и технический инициатор, и руководитель / ЛПР.","levels":[["Участники не подтверждены",0],["Только пользователь / мастер",5],["Есть руководитель 2 или 3 уровня",10],["Есть руководитель организации",15]]},{"block":"P","code":"P2","title":"Объект очистки определен","desc":"оценивает, есть ли конкретный объект, который будут чистить. Максимальный балл — если объект заранее выбран, сфотографирован и признан клиентом приоритетным.","levels":[["Объект не выбран",0],["Объект назван устно",5],["Объект назван и есть фото / видео",10],["Заполнена анкета (лили имеется аналог данных из анкеты) и есть фото",15]]},{"block":"P","code":"P3","title":"Загрязнение и текущий метод очистки описаны","desc":"оценивает, понятно ли, что именно нужно удалить и чем клиент чистит сейчас. Это важно, чтобы не ехать “просто показать аппарат”.","levels":[["Загрязнение не описано",0],["Описано только загрязнение",4],["Описаны загрязнение и текущий метод",7],["Заполнена анкета (лили имеется аналог данных из анкеты) и есть фото",10]]},{"block":"P","code":"P4","title":"Воздух и площадка подтверждены","desc":"оценивает готовность пневмосети и места проведения. Максимальный балл — если подтверждены давление, расход, подключение, доступ, безопасность и условия площадки.","levels":[["Данные по воздуху отсутствуют",0],["Подтверждено только давление",5],["Подтверждены давление и расход",10],["Заполнена анкета (лили имеется аналог данных из анкеты) и есть фото",15]]},{"block":"P","code":"P5","title":"Критерии успеха согласованы","desc":"оценивает, договорились ли заранее, что считается успешной демонстрацией. Это снижает споры после показа.","levels":[["Критерии не согласованы",0],["Есть устное ожидание результата",5],["Согласованы качество и время очистки",10],["Заполнена анкета (лили имеется аналог данных из анкеты) и есть фото",15]]},{"block":"P","code":"P6","title":"Коммерческий потенциал понятен","desc":"оценивает, есть ли связь между демонстрацией и будущей продажей. Максимальный балл — когда понятны модель, бюджет, срок и следующий коммерческий шаг.","levels":[["Коммерческий потенциал не понятен",0],["Есть общий интерес",5],["Понятна возможная модель или бюджет",10],["Понятны модель, бюджет, срок и следующий шаг",15]]},{"block":"P","code":"P7","title":"Логистика и бюджет выезда согласованы","desc":"оценивает, подготовлены ли маршрут, лед, транспорт, люди и бюджет. Максимальный балл — если выезд согласован до начала расходов.","levels":[["Логистика не согласована",0],["Согласованы маршрут и участники",5],["Согласованы маршрут, участники, лед, транспорт и бюджет",10]]},{"block":"P","code":"P8","title":"Карточка и акнета подготовки заполнена и направлена директору и координатору","desc":"формальный критерий дисциплины. Без заполненной карточки нельзя доказать качество подготовки.","levels":[["Карточка отсутствует",0],["Карточка заполнена частично",3],["Карточка заполнена полностью",5]]},{"block":"R","code":"R1","title":"Согласованный технический результат по очистке обознгаченных загрязнений в акнете/письме достигнут","desc":"оценивает, достигнута ли цель очистки, согласованная до демонстрации.","levels":[["Результат не достигнут",0],["Результат достигнут частично",8],["Результат достигнут полностью",15],["Результат достигнут лучше согласованных критериев",20]]},{"block":"R","code":"R2","title":"Измерения зафиксированы","desc":"оценивает, есть ли цифры, а не только впечатление. Максимальный балл — если зафиксированы время, расход льда, давление, сопло и площадь / деталь.","levels":[["Измерений нет",0],["Есть только фото / видео",5],["Есть время или расход льда",10],["Есть время, расход льда, давление, сопло и площадь / деталь",15]]},{"block":"R","code":"R3","title":"Клиент подтвердил результат","desc":"оценивает, кто со стороны клиента увидел и подтвердил результат. Максимальный балл — если результат подтвердил руководитель / ЛПР или технический руководитель.","levels":[["Подтверждения клиента нет",0],["Подтвердил пользователь / мастер",5],["Есть руководитель 2 или 3 уровня",10],["Есть руководитель организации",15]]},{"block":"R","code":"R4","title":"Следующий шаг после демонстрации получен","desc":"главный коммерческий критерий результата. Максимальный балл — если клиент запросил КП, счет, аренду, договор или повторный тест по конкретной сделке.","levels":[["Следующего шага нет",0],["Есть только устный интерес",5],["Назначена дата следующего контакта / встречи",12],["Запрошены КП, счет, аренда, договор или повторный тест",20]]},{"block":"R","code":"R5","title":"Отчет по демонстрации оформлен","desc":"отчет нужен для внутреннего согласования у клиента и для контроля внутри ИРБИСТЕХ.","levels":[["Отчета нет",0],["Есть краткий отчет с фото / видео",5],["Есть отчет с фото / видео, цифрами и выводом",10]]},{"block":"R","code":"R6","title":"Экономика для клиента посчитана","desc":"оценивает, удалось ли перевести технический результат в деньги: простой, труд, расходники, брак, ресурс оборудования.","levels":[["Экономика не обсуждалась",0],["Есть оценка эффекта словами",5],["Есть расчет в часах, рублях или человеко-часах",10]]},{"block":"R","code":"R7","title":"Причина неуспеха или отказа зафиксирована","desc":"этот критерий нужен, если демонстрация не привела сразу к продаже. Важно понять: проблема в технологии, клиенте, бюджете, воздухе, подготовке или сроках.","levels":[["Причина не зафиксирована",0],["Причина описана устно",5],["Причина зафиксирована письменно и есть дальнейшее решение",10]]},{"block":"M","code":"M1","title":"Стратегический статус клиента подтвержден","desc":"снижает вычет, если клиент важен для компании: крупный холдинг, отраслевой лидер, возможны повторные продажи или публичный кейс.","levels":[["Стратегический статус не запрашивался у директора",0],["Статус не директором до выезда",8],["Статус подтвержден директором до выезда",15]]},{"block":"M","code":"M4","title":"Логистика выезда оптимизирована","desc":"снижает вычет, если расходы распределяются не на одну демонстрацию, а на несколько задач маршрута.","levels":[["1 клиент Х демо",0],["2 клиент Х демо",5],["3 клиент Х демо и более",10]]},{"block":"M","code":"M6","title":"Демонстрация дала маркетинговую или R&D-ценность","desc":"снижает вычет, если демонстрация полезна не только для одной сделки, но и для будущих продаж: фото, видео, новый кейс, новая отрасль, проверка новой задачи.","levels":[["Материалы непригодны для повторного использования",0],["Материалы пригодны только внутри компании",7],["Материалы пригодны для кейса / маркетинга (фото 16:9 и видео 16:9)",15]]}],"expense_settings":[{"code":"d_driver_km","article":"Работа водителя за километраж по маячку А5/А6","section":"driver","unit":"км","qty_default":300,"price_net_default":0,"price_vat_default":0,"qty_manager":true,"price_manager":false,"calc_type":"office_driver_km","comment":"Количество вводит менеджер; ставка NET на руки подставляется по офису менеджера; НПД считается через 0.94"},{"code":"d_demo_work","article":"Работа демонстратора*","section":"driver","unit":"часы","qty_default":4,"price_net_default":1350,"price_vat_default":0,"qty_manager":false,"price_manager":false,"calc_type":"demo_work_total","comment":"Количество = время на административные процедуры + время работы на демонстрации; НПД считается через 0.94"},{"code":"d_night_compensation","article":"Компенсация за ночевку и другие согласованные расходы","section":"driver","unit":"руб. на руки","qty_default":0,"price_net_default":0,"price_vat_default":0,"qty_manager":true,"price_manager":false,"calc_type":"npd_cash_input","comment":"Менеджер вводит сумму на руки; НПД считается через 0.94"},{"code":"d_cryoblaster","article":"Демонстрация криобластера (1 демо = 1 точка Газели)","section":"driver","unit":"усл","qty_default":1,"price_net_default":0,"price_vat_default":0,"qty_manager":true,"price_manager":false,"calc_type":"office_cryoblaster","comment":"Количество вводит менеджер; ставка NET на руки подставляется по офису менеджера; НПД считается через 0.94"},{"code":"d_hard_conditions","article":"Усложненные условия труда","section":"driver","unit":"усл","qty_default":0,"price_net_default":1700,"price_vat_default":0,"qty_manager":true,"price_manager":false,"calc_type":"npd_direct","comment":"Жара/холод/дождь/снег/противогаз/грязная или шумная среда/улица/сложный допуск, если указано в акте"},{"code":"d_electric_compressor","article":"Работа с электрическим компрессором в фанере","section":"driver","unit":"усл","qty_default":0,"price_net_default":3500,"price_vat_default":0,"qty_manager":true,"price_manager":false,"calc_type":"npd_direct","comment":"Административная ставка; количество вводит менеджер"},{"code":"d_electro_reel","article":"Использование электрокатушки","section":"driver","unit":"усл","qty_default":1,"price_net_default":1000,"price_vat_default":0,"qty_manager":true,"price_manager":true,"calc_type":"npd_direct","comment":"Менеджер может менять количество и ставку NET на руки"},{"code":"d_load_unload","article":"Выгрузка и загрузка компрессора и электрокатушки","section":"driver","unit":"усл","qty_default":0,"price_net_default":2000,"price_vat_default":0,"qty_manager":true,"price_manager":true,"calc_type":"npd_direct","comment":"Снятие/монтаж ремней, подготовка к перемещению, перемещение на колесах/платформе или с механизацией"},{"code":"o_transport_fixed","article":"Расходы на перевозку чужим транспортом (туда-обратно)","section":"other","unit":"усл","qty_default":0,"price_net_default":2800,"price_vat_default":0,"qty_manager":true,"price_manager":true,"calc_type":"direct","comment":"Менеджерское поле"},{"code":"o_transport_km","article":"Расходы на перевозку чужим транспортом (туда-обратно)","section":"other","unit":"км","qty_default":0,"price_net_default":41,"price_vat_default":0,"qty_manager":true,"price_manager":true,"calc_type":"direct","comment":"Менеджерское поле по километражу стороннего транспорта"},{"code":"o_hotel_manager","article":"Расходы на отель Менеджера","section":"other","unit":"день х чел","qty_default":0,"price_net_default":2800,"price_vat_default":0,"qty_manager":true,"price_manager":true,"calc_type":"direct","comment":"Менеджерское поле"},{"code":"o_hotel_driver","article":"Расходы на отель Водителя","section":"other","unit":"день х чел","qty_default":0,"price_net_default":2800,"price_vat_default":0,"qty_manager":true,"price_manager":true,"calc_type":"direct","comment":"Менеджерское поле"},{"code":"o_manager_travel","article":"Расходы на переезд менеджера","section":"other","unit":"усл","qty_default":0,"price_net_default":3000,"price_vat_default":0,"qty_manager":true,"price_manager":true,"calc_type":"direct","comment":"Менеджерское поле"},{"code":"o_toll","article":"Расходы на платную дорогу (туда-обратно) по транспондеру","section":"other","unit":"усл","qty_default":0,"price_net_default":0,"price_vat_default":0,"qty_manager":true,"price_manager":false,"calc_type":"cash_amount_vat","comment":"Менеджер вводит сумму платежа; сумма попадает в расходы с НДС как в Excel"},{"code":"o_per_diem","article":"Суточные по командировки (при ночевке)","section":"other","unit":"день х чел","qty_default":1,"price_net_default":1500,"price_vat_default":0,"qty_manager":true,"price_manager":false,"calc_type":"direct","comment":"Количество вводит менеджер; ставка административная"},{"code":"o_diesel","article":"Расходы на дизель (15 л/100км), л","section":"other","unit":"литры","qty_default":0,"price_net_default":0,"price_vat_default":72,"qty_manager":false,"price_manager":true,"calc_type":"diesel","comment":"Количество = километраж / 100 × 15; цена с НДС вводится менеджером"},{"code":"o_gazelle_amort","article":"Амортизация Газели и ТО","section":"other","unit":"усл","qty_default":1,"price_net_default":0,"price_vat_default":0,"qty_manager":true,"price_manager":false,"calc_type":"office_gazelle_amort_total","comment":"Количество корректирует менеджер; административная ставка подставляется по офису менеджера"},{"code":"o_dry_ice_purchase","article":"Расходы на закупку сухого льда","section":"other","unit":"кг","qty_default":30,"price_net_default":0,"price_vat_default":110,"qty_manager":true,"price_manager":true,"calc_type":"direct_vat_price","comment":"Менеджерское поле: количество и цена с НДС"},{"code":"o_dry_ice_delivery","article":"Расходы на доставку сухого льда в цех","section":"other","unit":"усл","qty_default":0,"price_net_default":1500,"price_vat_default":0,"qty_manager":true,"price_manager":true,"calc_type":"direct","comment":"Менеджерское поле"}]}'::jsonb);
